head.script:
// 세션정보 가져오기
scwin.sUserId = "";

scwin.strFromDate = "";			// 현재년월일을 구한다.
scwin.strToDate = "";         // 현재일자를 구한다.
scwin.strDate = "";
scwin.tabNo = 0;

scwin.onpageload = function () {

    scwin.sUserId = $c.data.getMemInfo("userId");

    scwin.strFromDate = $c.date.getServerDateTime("yyyyMMdd").substring(0, 8);			// 현재년월일을 구한다.
    scwin.strToDate = $c.date.getServerDateTime("yyyyMMdd");	                        // 현재일자를 구한다.
    scwin.strDate = scwin.strFromDate + scwin.strToDate;


};

scwin.onUdcCompleted = function () {
    scwin.f_SetDefaultData();

    chb_previewCheck_storageCharge.hide();
    chb_printCheckPre_transCost.setValue(1);
    chb_printCheckPre_storageCharge.setValue(1);
}

scwin.f_SetDefaultData = function () {
    $c.gus.cfInitObjects(tb_srchCond, [udc_comCodeBilgLodept]);

    ed_closeYm.setValue(scwin.strFromDate);
    tac_tabControl1.setSelectedTabIndex(0);
    ed_closeYm.focus();
};

// 검색영역 Field Clear함.
scwin.f_InitObjects = function () {
    $c.gus.cfInitObjects(tb_mainData);
    scwin.f_SetDefaultData();
};

// 조회
scwin.f_Retrieve = async function () {

    // 검색조건 필수 입력 체크
    if (! await $c.gus.cfValidate([ed_closeYm])) {
        return;
    }

    $c.sbm.execute(sbm_retrieve);
};


// 저장
scwin.f_save = async function () {

    if (tac_tabControl1.getSelectedTabID() == "tabs1") {
        var argDs = ds_transCost;
    } else if (tac_tabControl1.getSelectedTabID() == "tabs2") {
        var argDs = ds_storageCharge;
    }

    var msg = "";
    var amtGb = "";
    var yyyyMm = ed_closeYm.getValue();

    if (!$c.gus.cfValidate([ed_closeYm])) {
        return;
    }

    if (!$c.data.isModified(argDs)) {
        $c.gus.cfAlertMsg("변경된 사항이 없습니다.");
        return;
    }

    mag = yyyyMm.substring(0, 4) + "년 " + yyyyMm.substring(4, 6) + "월 이미 등록된 마감자료의 경우 삭제후 저장됩니다.";

    if (tac_tabControl1.getSelectedTabID() == "tabs1") {
        msg = mag + " \n운송비 최종마감자료를 저장 하시겠습니까?";
        amtGb = "01";

    } else if (tac_tabControl1.getSelectedTabID() == "tabs2") {
        msg = mag + " \n보관비 최종마감자료를 저장 하시겠습니까?";
        amtGb = "02";
    }

    var arrDupChk = "";

    let rtn = await $c.win.confirm(msg);
    if (rtn) {  // 리턴 처리


        if (argDs.getRowCount() > 0) {

            ds_master.setData([]);

            for (i = 0; i < argDs.getRowCount(); i++) {
                if (arrDupChk.indexOf(argDs.getCellData(i, "odrNo") + "V" + argDs.getCellData(i, "sellSeq")) > -1) {
                    $c.gus.cfAlertMsg("데이터 중복 오류\n오더번호 : " + argDs.getCellData(i, "odrNo") + "\n오더순번 : " + argDs.getCellData(i, "sellSeq"));
                    return;
                }

                arrDupChk = arrDupChk + argDs.getCellData(i, "odrNo") + "V" + argDs.getCellData(i, "sellSeq");
                let nRow = ds_master.insertRow();
                //                row = ds_master.getRowCount();

                ds_master.setCellData(nRow, "amtGb", amtGb);
                ds_master.setCellData(nRow, "closeYm", yyyyMm);
                ds_master.setCellData(nRow, "odrNo", argDs.getCellData(i, "odrNo"));
                ds_master.setCellData(nRow, "sellSeq", argDs.getCellData(i, "sellSeq"));
                ds_master.setCellData(nRow, "mchtOdrNo", argDs.getCellData(i, "mchtOdrNo"));
                ds_master.setCellData(nRow, "wrkWt", argDs.getCellData(i, "wrkWt"));
                ds_master.setCellData(nRow, "sellUpr", argDs.getCellData(i, "sellUpr"));
                ds_master.setCellData(nRow, "sellAmt", argDs.getCellData(i, "sellAmt"));
                ds_master.setCellData(nRow, "vatAmt", argDs.getCellData(i, "vatAmt"));
                ds_master.setCellData(nRow, "clntCommCd", argDs.getCellData(i, "clntCommCd"));
                ds_master.setCellData(nRow, "qtyUnitCd", argDs.getCellData(i, "qtyUnitCd"));
                ds_master.setCellData(nRow, "smQty", argDs.getCellData(i, "smQty"));
                ds_master.setCellData(nRow, "unitCd", argDs.getCellData(i, "unitCd"));
                ds_master.setCellData(nRow, "ioDt", argDs.getCellData(i, "ioDt"));
                ds_master.setCellData(nRow, "selfVehclNo", argDs.getCellData(i, "selfVehclNo"));
                ds_master.setCellData(nRow, "transWrkIndictNo", argDs.getCellData(i, "transWrkIndictNo"));
                ds_master.setCellData(nRow, "wrkQty", argDs.getCellData(i, "wrkQty"));

                if (tac_tabControl1.getSelectedTabID() == "tabs1") { // 운송비
                    ds_master.setCellData(nRow, "excAmt", argDs.getCellData(i, "excAmt"));
                    ds_master.setCellData(nRow, "totAmt", argDs.getCellData(i, "totAmt"));
                    ds_master.setCellData(nRow, "holidayYn", argDs.getCellData(i, "holidayYn"));
                    ds_master.setCellData(nRow, "rmk", argDs.getCellData(i, "rmk"));
                } else if (tac_tabControl1.getSelectedTabID() == "tabs2") { // 보관비
                    ds_master.setCellData(nRow, "selfTransYn", argDs.getCellData(i, "selfTransYn"));
                    ds_master.setCellData(nRow, "totAmt", argDs.getCellData(i, "sellAmt"));
                }

                if ($c.gus.cfIsNull(argDs.getCellData(i, "warehouseNm")) == true) {
                    $c.gus.cfAlertMsg("[" + i + "] 번째 행의 [창고명] 값이 없습니다.\n사용하신 엑셀파일의 데이터를 확인 후,\n다시 업로드하시길 바랍니다.");
                    return;

                } else {
                    if ($c.str.trim(argDs.getCellData(i, "warehouseNm")) == "기흥창고") {
                        ds_master.setCellData(nRow, "sellLodeptCd", "4G1");
                    } else if ($c.str.trim(argDs.getCellData(i, "warehouseNm")) == "오류창고") {
                        ds_master.setCellData(nRow, "sellLodeptCd", "4H3");
                    } else if ($c.str.trim(argDs.getCellData(i, "warehouseNm")) == "광주창고") {
                        ds_master.setCellData(nRow, "sellLodeptCd", "5A6");
                    }
                }
            }
        }

        $c.sbm.execute(sbm_save);
    }
};


//탭1 엑셀 다운
scwin.f_gridToExcelTransCost = async function (argGrid, argTitle) {
    //    if (ds_transCost.getRowCount() != 0) {
    cfrm = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");

    if (cfrm) {
        const options = {
            fileName: "크나우프 " + "마감자료(운송비)" + "_" + ed_closeYm.getValue(),
            sheetName: "크나우프 " + "마감자료(운송비)" + "_" + ed_closeYm.getValue()
        };

        $c.data.downloadGridViewExcel(gr_transCost, options);
    }
    // } else {
    //     $c.gus.cfAlertMsg(MSG_CM_WRN_002);
    //     return;
    // }
};

//탭2 엑셀 다운
scwin.f_gridToExcelStorageCharge = async function (argGrid, argTitle) {
    //    if (ds_storageCharge.getRowCount() != 0) {
    cfrm = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");
    if (cfrm) {
        const options = {
            fileName: "크나우프 " + "마감자료(보관비)" + "_" + ed_closeYm.getValue(),
            sheetName: "크나우프 " + "마감자료(보관비)" + "_" + ed_closeYm.getValue()
        };
        $c.data.downloadGridViewExcel(gr_storageCharge, options);
    }
    // } else {
    //     $c.gus.cfAlertMsg(MSG_CM_WRN_002);
    //     return;
    // }
};

//거래명세서 출력(전표번호) 
scwin.f_Print = async function () {

    var ozMode = "";
    var argDs = ds_transCost;
    if (tac_tabControl1.getSelectedTabID() == "tabs1") {
        argDs = ds_transCost;
        if (chb_printCheckPre_transCost.getValue() != true) { // 미리보기만 체크된 경우
            ozMode = "export";
        } else {
            ozMode = "silent";
        }
    } else if (tac_tabControl1.getSelectedTabID() == "tabs2") {
        argDs = ds_storageCharge;
        if (chb_printCheckPre_storageCharge.getValue() != true) { // 미리보기만 체크된 경우
            ozMode = "export";
        } else {
            ozMode = "silent";
        }
    }

    if (argDs.getRowCount() > 0) {

        var data = {
            // 쿼리(ODI)에 적용할 파라미터를 설정(OZParam)
            reportName: "ds/op/wrkrslts/transwrkrslts/op_304_01_68p.ozr",
            odiParam: {
                CLOSE_YM: ed_closeYm.getValue()
            },
            viewerParam: {
                useprogressbar: false, // 프로그레스바 쓸지 말지
                zoom: 100, // 배율 설정
                mode: ozMode
            },
            formParam: {

            }
        };

        let opts = {
            id: "ozReportPopup",
            popupName: "오즈 리포트",
            modal: true,
            type: "browserPopup",
            width: 1000,
            height: 600,
            title: "오즈 리포트"
        };
        await $c.win.openPopup("/ui/cm/zz/ozreportPopup.xml", opts, data);

    }
};


scwin.f_selectTabMenu = function (info) {
    if (tac_tabControl1.getSelectedTabIndex() == 0) {
        chb_printCheck_transCost.show("");
        chb_previewCheck_storageCharge.hide();

    } else if (tac_tabControl1.getSelectedTabIndex() == 1) {
        chb_printCheck_transCost.hide();
        chb_previewCheck_storageCharge.show("");
    }
};


scwin.f_openCommonPopUp = async function (pClose, pAllSearch) {
    // 작업장
    udc_comCodeBilgLodept.cfCommonPopUp(
        scwin.udc_comCodeBilgLodept_callBackFunc,
        ed_bilgLodeptCd.getValue(),
        ed_bilgLodeptNm.getValue(),
        pClose, //pClose
        null,
        null,
        null,
        null,
        null,
        null,
        null,
        null,
        null,
        null,
        pAllSearch, //pAllSearch
        null,
        null
    );
};

scwin.udc_comCodeBilgLodept_callBackFunc = function (ret) {
    // console.log(ret); 
    $c.gus.cfSetReturnValue(ret, ed_bilgLodeptCd, ed_bilgLodeptNm);
};


scwin.udc_comCodeBilgLodept_onclickEvent = function (e) {
    scwin.f_openCommonPopUp("F", "F");
};

scwin.udc_comCodeBilgLodept_onblurCodeEvent = function (e) {
    scwin.f_openCommonPopUp("T", "T");
};

scwin.udc_comCodeBilgLodept_onviewchangeNameEvent = function (info) {
    scwin.f_openCommonPopUp("T", "T");
};


scwin.sbm_retrieve_submitdone = function (e) {
    if (tac_tabControl1.getSelectedTabID() == "tabs1") {
        if (ds_transCost.getRowCount() == 0) {
            $c.gus.cfAlertMsg(MSG_CM_ERR_003);  // 해당되는 자료가 존재하지 않습니다
        }
    } else if (tac_tabControl1.getSelectedTabID() == "tabs2") {
        if (ds_storageCharge.getRowCount() == 0) {
            $c.gus.cfAlertMsg(MSG_CM_ERR_003);  // 해당되는 자료가 존재하지 않습니다
        }
    }
    totalRows_transCost.setValue(ds_transCost.getRowCount());
    totalRows_storageCharge.setValue(ds_storageCharge.getRowCount());
}

scwin.sbm_save_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
        scwin.f_Retrieve();
    }
};


////////////////////////////////////// 엑셀 다운로드 및 업로드 관련 함수 /////////////////////////////////

//-------------------------------------------------------------------------
// 엑셀 업로드
//-------------------------------------------------------------------------
scwin.f_upload = async function () {

    ds_transCost.setJSON([]);
    ds_transCostExcel.setJSON([]);

    await $c.win.alert("uploding할 엑셀파일에 ',' 가 있다면, 잘못된 정보가 올라갈수 있으니, 제거해주시기 바랍니다.");

    let options = {
        "fileName": "gridDataUpload.xlsx",
        "status": "C",
        "headerExist": 1,
        "useMaxByteLength": ",",
        "type": "1",
        "startRowIndex": 0,
        "footerExist": "0"
    };
    await udc_topGrdBtnTransCost.uploadGridViewExcel(gr_transCostExcel, options);
    //    await $c.data.uploadGridViewExcel(gr_transCostExcel, options);
};

scwin.gr_transCostExcel_onfilereadend = function (value) {
    if (ds_transCostExcel.getRowCount() === 0) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_003);
        return;
    }
    var options = {};
    options.sortIndex = "odrNo sellSeq"; // DataList의 컬럼 ID 또는 Index. 공백으로 컬럼을 구분합니다.
    options.sortOrder = "-1 -1"; // 정렬 기준으로 공백으로 구분합니다. 1:오름차순, -1:내림차순

    ds_transCostExcel.multisort(options);

    var dtCnt = ds_transCostExcel.getRowCount();
    ds_transCostExcel.setBroadcast(false);
    for (let idx = dtCnt - 1; idx >= 0; idx--) {
        let warehouseNm = ds_transCostExcel.getCellData(idx, "warehouseNm");
        //            let salePlCoNm  = ds_excel.getCellData(idx, "salePlCoNm");

        if ($c.gus.cfIsNull(warehouseNm) || $c.str.trim(warehouseNm) == "창고명") {

            console.log("odrNo, newSellUpr ERROR");
            ds_transCostExcel.removeRow(idx);
            continue;
        }
    }
    ds_transCostExcel.setBroadcast(true);

    const data2 = JSON.parse(JSON.stringify(ds_transCostExcel.getAllJSON()));
    ds_transCost.setJSON(data2);

    ds_transCost.modifyAllStatus("C");
    $c.gus.cfAlertMsg("업로드작업이 완료되었습니다.");
};

scwin.f_uploadStorageCharge = async function () {

    ds_storageCharge.setJSON([]);
    ds_storageChargeExcel.setJSON([]);

    await $c.win.alert("uploding할 엑셀파일에 ',' 가 있다면, 잘못된 정보가 올라갈수 있으니, 제거해주시기 바랍니다.");

    let options = {
        "fileName": "gridDataUpload.xlsx",
        "status": "C",
        "headerExist": 1,
        "useMaxByteLength": ",",
        "type": "1",
        "startRowIndex": 0,
        "footerExist": "0"
    };

    await udc_topGrdBtnStorageCharge.uploadGridViewExcel(gr_storageChargeExcel, options);
    //  await $c.data.uploadGridViewExcel(gr_storageChargeExcel, options);
};

scwin.gr_storageChargeExcel_onfilereadend = function (value) {
    if (ds_storageChargeExcel.getRowCount() === 0) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_003);
        return;
    }
    var options = {};
    options.sortIndex = "odrNo sellSeq"; // DataList의 컬럼 ID 또는 Index. 공백으로 컬럼을 구분합니다.
    options.sortOrder = "-1 -1"; // 정렬 기준으로 공백으로 구분합니다. 1:오름차순, -1:내림차순

    ds_storageChargeExcel.multisort(options);

    var dtCnt = ds_storageChargeExcel.getRowCount();
    ds_storageChargeExcel.setBroadcast(false);
    for (let idx = dtCnt - 1; idx >= 0; idx--) {
        let warehouseNm = ds_storageChargeExcel.getCellData(idx, "warehouseNm");
        let salePlCoNm = ds_storageChargeExcel.getCellData(idx, "salePlCoNm");
        let odrNo = ds_storageChargeExcel.getCellData(idx, "odrNo");
        let sellSeq = ds_storageChargeExcel.getCellData(idx, "sellSeq");
        let bizLongNm = ds_storageChargeExcel.getCellData(idx, "bizLongNm");

        if ($c.gus.cfIsNull(warehouseNm) || $c.str.trim(warehouseNm) == "창고명") {

            console.log("odrNo, newSellUpr ERROR");
            ds_storageChargeExcel.removeRow(idx);
            continue;
        }

        if (salePlCoNm != "고정보관비") {
            if ($c.gus.cfIsNull(odrNo) || $c.gus.cfIsNull(sellSeq)) {
                //                 // (오더번호 AA 27) , (오더순번 AB 28) 에 null이나 공백이 있을경우 경고메세지 출력후 종료 

                $c.gus.cfAlertMsg("업로드 엑셀파일의 데이터가 잘못되었습니다." + "\n[" + idx + "] 번째 행의 [오더번호 또는 오더순번] 값이 없습니다.\n사용하신 엑셀파일의 데이터를 확인 후,\n다시 업로드하시길 바랍니다.");
                return;
            }
        } else if (salePlCoNm == "고정보관비") {
            ds_storageChargeExcel.setCellData(idx, "odrNo", "고정보관비");
            ds_storageChargeExcel.setCellData(idx, "sellSeq", idx);
            ds_storageChargeExcel.setCellData(idx, "mchtOdrNo", bizLongNm);

            //                 ds_excel.NameValue(i, ds_excel.ColumnID(27)) = "고정보관비";
            //                 ds_excel.NameValue(i, ds_excel.ColumnID(28)) = i;
            //                 ds_excel.NameValue(i, ds_excel.ColumnID(5)) = ds_excel.NameValue(i, ds_excel.ColumnID(2));//크나우프오더번호 E > 사업장 매핑
        } else {
            $c.gus.cfAlertMsg("업로드 엑셀파일의 데이터가 잘못되었습니다." + "\n[" + idx + "] 번째 행의 값이 없습니다.\n사용하신 엑셀파일의 데이터를 확인 후,\n다시 업로드하시길 바랍니다.");
        }
    }
    ds_storageChargeExcel.setBroadcast(true);

    const data2 = JSON.parse(JSON.stringify(ds_storageChargeExcel.getAllJSON()));
    ds_storageCharge.setJSON(data2);

    ds_storageCharge.modifyAllStatus("C");
    $c.gus.cfAlertMsg("업로드작업이 완료되었습니다.");
};

scwin.ds_transCost_ondataload = function () {
    totalRows_transCost.setValue(ds_transCost.getRowCount());
};

scwin.ds_storageCharge_ondataload = function () {
    totalRows_storageCharge.setValue(ds_storageCharge.getRowCount());
};

scwin.f_FieldClear = function (e) {
    scwin.f_SetDefaultData();
};
